// ============================================
// VALIDAR INPUT + DETECTAR CONTACTO NUEVO
// ============================================
const payload = $input.item.json.body || $input.item.json;

// Campos del evento
const event = payload.event;
const content = payload.content || '';
const conversation_id = payload.conversation?.id;
const inbox_id = payload.conversation?.inbox_id;
const clinic_id = payload.conversation?.custom_attributes?.clinic_id;
const patient_id = payload.conversation?.custom_attributes?.patient_id;
const contact_phone = payload.conversation?.contact_inbox?.source_id;
const contact_id = payload.sender?.id;
const channel_type = payload.conversation?.contact_inbox?.inbox?.channel_type;
// CTWA (Click-to-WhatsApp) — detect when lead came from a Meta ad
const _referral      = (payload.content_attributes || {}).referral || {};
const is_ctwa_lead   = !!(_referral.ctwa_clid);
const ctwa_clid      = _referral.ctwa_clid      || null;
const ctwa_source_id = _referral.source_id      || null;
const ctwa_headline  = _referral.headline       || null;
const ctwa_body      = _referral.body           || null;

const account_id = payload.account?.id || 2;
const message_type = payload.message_type;
const created_at = payload.created_at;

// Early exit: outgoing/activity messages are SofIA's own responses
// Stops execution after 3 nodes instead of running 9 before IsUserMessage filter
if (message_type === 'outgoing' || message_type === 'activity') {
  return [];
}

// Obtener contador de interacciones bot
const bot_count = payload.conversation?.custom_attributes?.bot_interaction_count || 0;
const last_bot_message = payload.conversation?.custom_attributes?.last_bot_message_at;
const contact_inboxes = payload.conversation?.contact_inbox;
const has_contact_inbox = !!contact_inboxes;

return [{
  json: {
    message_text: (content || '').trim(),
    conversation_id: conversation_id,
    inbox_id: inbox_id,
    inbox_id_api: 2,
    inbox_id_db: 3,
    clinic_id: clinic_id || 'default',
    patient_id: patient_id,
    contact_phone: contact_phone,
    contact_id: contact_id,
    account_id: account_id,
    message_type: message_type,
    message_timestamp: created_at,
    bot_interaction_count: bot_count,
    last_bot_message_at: last_bot_message,
    sender_name: payload.sender?.name || 'Paciente',
    sender_email: payload.sender?.email,
    conversation_status: payload.conversation?.status,
    has_contact_inbox: has_contact_inbox,
    channel_type: channel_type || 'Channel::WebWidget',
    is_ctwa_lead: is_ctwa_lead,
    ctwa_clid: ctwa_clid,
    ctwa_source_id: ctwa_source_id,
    ctwa_headline: ctwa_headline,
    ctwa_body: ctwa_body,
    raw_payload: payload
  }
}];

// WHATSAPP SAFE RULES - SofIA 24/7
const ctx           = $input.first().json;
const bot_count     = ctx.bot_interaction_count || 0;
const raw           = (ctx.message_text || "");
const message_lower = raw.toLowerCase();
// Normalize: remove accents, replace common typos
const msgNorm = message_lower.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

// Regla 1: Maximo 10 interacciones automaticas
if (bot_count >= 10) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MAX_INTERACTIONS_PHASE1",
    escalation_message: "Te conecto con un agente de inmediato. Un momento." } }];
}

// Regla 2: Mensaje > 24h (muy antiguo)
const message_age_hours = (Date.now() - (ctx.message_timestamp * 1000)) / 3600000;
if (message_age_hours > 24) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "MESSAGE_TOO_OLD",
    escalation_message: "Te conecto con un agente." } }];
}

// Regla 3: Emergencias — normalized check (handles typos and variations)
const emergency_kws = [
  "emergencia","emrgencia","urgencia","urgente",
  "dolor fuerte","sangra","sangrado","mucho dolor","me duele mucho","duele mucho",
  "muela rota","golpe","accidente","hinchazon","infeccion","inflamacion","fiebre",
  "caida","fractura","trauma","absceso","quiste",
  "dolor de muela","me duele la muela","me duele una muela","dolor muela",
  "duele el diente","duele la muela","muela hinchada","cara hinchada",
  "no puedo dormir del dolor","llevo dias con dolor","tengo mucho dolor"
];
if (emergency_kws.some(function(kw) { return msgNorm.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "EMERGENCY_DETECTED",
    escalation_message: "\u26a0\ufe0f Entiendo que tienes molestias dentales. Te conecto con nuestro equipo de inmediato para atenderte.", priority: "urgent" } }];
}

// Regla 4: Opt-out explicito
const opt_out_kws = ["detente","ya no","basta","stop","cancelar bot","agente","humano","persona real","hablar con alguien","quiero hablar con"];
if (opt_out_kws.some(function(kw) { return message_lower.includes(kw); })) {
  return [{ json: { ...ctx, should_escalate: true, escalation_reason: "USER_OPT_OUT",
    escalation_message: "Entendido. Te conecto con un agente ahora mismo." } }];
}

// SofIA responde 24/7 sin restriccion de horario
return [{ json: { ...ctx, should_escalate: false, whatsapp_safe: true,
  debug_bot_count: bot_count, checked_at: new Date().toISOString() } }];

// NORMALIZAR OUTPUT DEL CLASIFICADOR
// Keyword path: context is intact in $json
if ($json.skip_ai === true && $json.intent) {
    const intent = $json.intent;
    // GREETING is now handled by ¿Es MENU o GREETING? — do NOT convert to INFO
    return [{ json: Object.assign({}, $json, { intent: intent, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_PRE_CLASSIFIER" }) }];
}

// AI path: restore context from Pre-Clasificador Keywords node
const ctx = $node["Pre-Clasificador Keywords"].json;
let intent_data = $json.output || $json;
if (typeof intent_data === "string") {
    try { intent_data = JSON.parse(intent_data); }
    catch(e) {
        const t = intent_data.toLowerCase();
        if (t.includes("create_event")) intent_data = { intent: "CREATE_EVENT", confidence: "low" };
        else if (t.includes("info"))   intent_data = { intent: "INFO",         confidence: "low" };
        else if (t.includes("payment")) intent_data = { intent: "PAYMENT",     confidence: "low" };
        else intent_data = { intent: "HUMAN", confidence: "low" };
    }
}
let intent = (intent_data.intent || "HUMAN").trim().toUpperCase();
let confidence = (intent_data.confidence || "low").toLowerCase();
const valid = ["CREATE_EVENT","INFO","PAYMENT","HUMAN"];
if (!valid.includes(intent)) { intent = "HUMAN"; confidence = "low"; }
return [{ json: Object.assign({}, ctx, { intent: intent, confidence: confidence, classified_at: new Date().toISOString(), phase: "PHASE_1_WITH_AI_CLASSIFIER" }) }];

// PREPARAR ESCALADO — pausa el bot en Supabase governance
const ctx = $json;
const escalationMsg = ctx.escalation_message
  || (ctx.bot_config && ctx.bot_config.escalation_message)
  || (ctx.intent === 'PAYMENT'
    ? 'Perfecto, te conecto con un asesor para ayudarte con el pago. Un momento por favor \ud83d\ude4f'
    : ctx.intent === 'HUMAN'
    ? 'Entendido! Te conecto con uno de nuestros asesores ahora mismo. Un momento \ud83d\ude4f'
    : 'Te conecto con nuestro equipo enseguida. Un momento por favor \ud83d\ude4f');

// Intentar pausar el bot en Supabase (fail-safe: no bloquea el flujo)
const govId = ctx.governance_conversation_id;
const isDemoModeEsc = (ctx.bot_config && ctx.bot_config.demo_mode === true);
if (govId && !isDemoModeEsc) {
  const SUPABASE_URL = $env.N8N_SUPABASE_URL;
  const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/rpc/pause_conversation',
      headers: {
        'apikey':        SERVICE_KEY,
        'Authorization': 'Bearer ' + SERVICE_KEY,
        'Content-Type':  'application/json'
      },
      body: {
        p_conversation_id: govId,
        p_clinic_id:       ctx.clinic_id,
        p_user_role:       'admin'
      },
      json: true
    });
    console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'BOT_PAUSED', gov_id: govId }));
  } catch(e) {
    // Non-fatal: log but continue with escalation
    console.warn(JSON.stringify({ ts: new Date().toISOString(), event: 'BOT_PAUSE_FAILED', error: e.message }));
  }
}



// ── ESCALATION TRACKING (fail-safe) ────────────────────────────────────────
// Logs escalation event. Requires migration 027. Fails silently if not applied.
const rawPhone027esc = ctx.contact_phone || '';
if (ctx.clinic_id && rawPhone027esc) {
  const SUPA_ESC = $env.N8N_SUPABASE_URL;
  const SK_ESC   = $env.N8N_SUPABASE_SERVICE_KEY;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPA_ESC + '/rest/v1/rpc/log_clinical_event',
      headers: { apikey: SK_ESC, Authorization: 'Bearer ' + SK_ESC, 'Content-Type': 'application/json' },
      body: {
        p_clinic_id: ctx.clinic_id, p_event_type: 'escalation',
        p_phone: rawPhone027esc,
        p_summary: 'Escalado a agente. Intent: ' + (ctx.intent || 'unknown'),
        p_metadata: { intent: ctx.intent, conversation_id: ctx.conversation_id, gov_id: govId || null },
        p_created_by: 'bot'
      },
      json: true
    });
    console.log(JSON.stringify({ ts: new Date().toISOString(), event: 'ESCALATION_TRACKED' }));
  } catch(e027esc) {
    console.warn(JSON.stringify({ ts: new Date().toISOString(), event: 'ESCALATION_TRACK_SKIP', reason: e027esc.message.slice(0,80) }));
  }
}
// ── END ESCALATION TRACKING ────────────────────────────────────────────────

return [{
  json: {
    ...ctx,
    escalation_message_final: escalationMsg,
    escalation_reason_final:  ctx.escalation_reason || ('HUMAN_' + ctx.intent),
    internal_note: 'SofIA — Escalado a agente. Intent: ' + ctx.intent,
    is_urgent: ctx.priority === 'urgent',
    bot_paused: govId ? true : false
  }
}];

const item = $input.first().json;
const botConfig = item.bot_config || {};
const _msgText = item.escalation_message_final || "";
try {
  await this.helpers.httpRequest({
    method: "POST",
    url: "https://chat.redsolucionesti.com/api/v1/accounts/" + item.account_id + "/conversations/" + item.conversation_id + "/messages",
    headers: { "api_access_token": item.chatwoot_api_token, "Content-Type": "application/json" },
    body: JSON.stringify({ content: _msgText, message_type: "outgoing", private: false })
  });
} catch(_ce) {}
return [{ json: item }];

const message_text = $json.message_text || "";
const clinic_name = $json.clinic_name || "la clinica";
const isGreeting = $json.is_greeting === true;
const isThanks = $json._is_thanks === true;
const welcomeMsg = $json.welcome_message_text || ("\u00a1Hola! \ud83d\ude0a Soy SofIA de " + clinic_name + ". \u00bfEn qu\u00e9 puedo ayudarte?");
const kb_context = $json.kb_context || "";
var system_prompt, user_prompt;

// ── DEMO MODE: SofIA se presenta como producto ────────────────────────────
const isDemoMode = ($json.bot_config || {}).demo_mode === true;
if (isDemoMode) {
  var noKbDemo = "No hay informacion especifica disponible.";
  var kbSection = (kb_context && kb_context !== noKbDemo) ? "INFORMACION SOBRE SOFIA AI:\n" + kb_context + "\n\n" : "";
  var demoPrompt = [
    "Eres SofIA, asistente virtual con IA para clinicas dentales de Red Soluciones TI (Peru). Estas en modo DEMO mostrando tus capacidades.",
    "",
    kbSection,
    "REGLAS CRITICAS:",
    "- NUNCA empieces con 'Hola', saludos ni presentacion. El usuario ya sabe quien eres.",
    "- Maximo 60 palabras. Directo al punto.",
    "- 1-2 emojis maximo.",
    "- NUNCA listas numeradas — texto fluido.",
    "- Si la pregunta es sobre un servicio o precio, menciona brevemente el beneficio y termina con CTA corto (ej: 'Agenda tu demo sin costo').",
    "- Si el usuario YA pidio agendar o esta en proceso de agendar, NO repitas que puede agendar — solo responde la pregunta directamente.",
    "- Habla como SofIA explicando sus propias capacidades con confianza y entusiasmo."
  ].join("\n");
  return [{ json: Object.assign({}, $json, { system_prompt: demoPrompt, user_prompt: message_text, _prompt_ready: true }) }];
}

// ── THANKS ────────────────────────────────────────────────────────────────
if (isThanks) {
  system_prompt = "Eres SofIA, asistente virtual de la clinica dental " + clinic_name + ". El paciente acaba de agradecer. Responde con un cierre cordial y amable en 1 sola linea, en espanol informal (usa 'tu'). Ejemplo: '\u00a1Con mucho gusto! Cuando necesites algo mas, aqui estamos \ud83d\ude0a'. NO hagas preguntas adicionales.";
  user_prompt = message_text;
  return [{ json: Object.assign({}, $json, { system_prompt, user_prompt, _prompt_ready: true }) }];
}

// ── GREETING ──────────────────────────────────────────────────────────────
if (isGreeting) {
  var greetingCtx = $json.patient_ctx || { known: false };
  var greetMsg = welcomeMsg;
  if (greetingCtx.known && greetingCtx.full_name) {
    var firstName = greetingCtx.full_name.split(' ')[0];
    greetMsg = "\u00a1Hola " + firstName + "! \ud83d\ude0a Bienvenido/a de vuelta a " + clinic_name + ". \u00bfEn qu\u00e9 te puedo ayudar?";
  }
  system_prompt = "Eres SofIA, asistente virtual de " + clinic_name + ". El paciente te saludo. Responde EXACTAMENTE con: \"" + greetMsg + "\" No agregues nada mas.";
  user_prompt = message_text;
  return [{ json: Object.assign({}, $json, { system_prompt, user_prompt, _prompt_ready: true }) }];
}

// ── NORMAL INFO ───────────────────────────────────────────────────────────
var noKb = "No hay informacion especifica disponible. Ofrece agendar una cita o conectar con un agente.";
var kbSectionNormal = (kb_context && kb_context !== noKb) ? "INFORMACION DE LA CLINICA:\n" + kb_context + "\n\n" : "";

// Contexto del paciente (historial clinico para personalizar la respuesta)
var patientCtxData = $json.patient_ctx || { known: false };
var patientSection = "";
if (patientCtxData.known) {
  var pParts = ["HISTORIAL DEL PACIENTE:", patientCtxData.summary];
  if (patientCtxData.has_allergies && patientCtxData.allergy_alert) {
    pParts.push("ALERTA ALERGIAS: " + patientCtxData.allergy_alert + " (mencionalo si el tratamiento es relevante)");
  }
  patientSection = pParts.join("\n") + "\n\n";
}

var lines = [
  "Eres SofIA, asistente virtual de la clinica dental " + clinic_name + ". Tu rol es el de una RECEPCIONISTA HUMANA amable y profesional.",
  "",
  kbSectionNormal,
  patientSection,
  "REGLAS ESTRICTAS (seguir SIEMPRE):",
  "",
  "TONO Y ESTILO:",
  "- Habla como una recepcionista real: natural, calida, directa. NUNCA robotica.",
  "- Responde en espanol informal (usa 'te', 'tu', NUNCA 'usted').",
  "- Maximo 60 palabras. Se concisa.",
  "- Usa maximo 1-2 emojis por respuesta, solo cuando anaden calidez natural.",
  "- NUNCA hagas listas numeradas. NUNCA uses *1.* *2.* ni opciones enumeradas.",
  "- Termina con UNA pregunta corta y natural.",
  "",
  "CONTENIDO:",
  "- Usa SOLO la informacion de la clinica proporcionada arriba.",
  "- Si no tienes el dato exacto: da una respuesta util generica y ofrece conectar con el equipo.",
  "- NUNCA inventes precios, horarios, nombres de doctores ni direcciones.",
  "- NUNCA digas 'no tengo esa informacion' a secas — siempre ofrece una alternativa util.",
  "",
  "CASOS ESPECIALES:",
  "ROBOT / IA: 'Soy SofIA, la asistente virtual de la clinica \ud83d\ude0a Estoy aqui para ayudarte igual que una recepcionista. \u00bfEn que te puedo ayudar?'",
  "INGLES: 'Hi! I am SofIA \ud83e\uddb7 I can help you in English. What do you need?'",
  "MIEDO AL DENTISTA: 'Es completamente normal sentir nervios \ud83d\ude0a Nuestro equipo es muy gentil y trabaja sin prisa. \u00bfQuieres saber como es la primera consulta?'"
];

system_prompt = lines.join("\n");
user_prompt = message_text;
return [{ json: Object.assign({}, $json, { system_prompt, user_prompt, _prompt_ready: true }) }];

// Extraer respuesta del LLM
const response = $json;

// La respuesta de OpenAI viene en response.choices[0].message.content
const llm_response = response.choices?.[0]?.message?.content || '';

// Obtener datos originales del nodo "Preparar Prompt INFO"
const original_data = $node["Preparar Prompt INFO"].json;

return [{
  json: {
    ...original_data,  // Todos los datos originales (conversation_id, account_id, etc.)
    llm_response: llm_response.trim()
  }
}];

// ============================================
// VALIDACION ANTI-ALUCINACION
// ============================================

const llm_response = $json.llm_response || '';

// Flags de validación
let should_escalate = false;
let escalation_reason = '';

// Regla 1: Respuesta muy larga (>800 chars)
if (llm_response.length > 800) {
  should_escalate = true;
  escalation_reason = 'Respuesta LLM muy larga (>800 chars)';
}

// Regla 2: LLM explicitamente dice que no puede responder
// Be precise — only escalate if the LLM clearly says it lacks info
const no_info_exact = [
  'no tengo esa informacion',
  'no dispongo de esa informacion',
  'no cuento con esa informacion',
  'no tengo informacion sobre eso',
  'no está disponible en mis datos',
  'no puedo responder esta pregunta',
  'no tengo acceso a esa informacion'
];

const normalized_resp = llm_response.toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "");
for (const keyword of no_info_exact) {
  if (normalized_resp.includes(keyword)) {
    should_escalate = true;
    escalation_reason = 'LLM indica falta de informacion especifica';
    break;
  }
}

// Regla 3: Respuesta vacía o muy corta
if (llm_response.length < 10) {
  should_escalate = true;
  escalation_reason = 'Respuesta LLM vacia o muy corta';
}

return [{
  json: {
    ...($json || {}),
    should_escalate_info: should_escalate,
    escalation_reason_info: escalation_reason,
    validation_passed: !should_escalate
  }
}];

const item = $input.first().json;
const botConfig = item.bot_config || {};
const _msgText = item.llm_response || "";
try {
  await this.helpers.httpRequest({
    method: "POST",
    url: "https://chat.redsolucionesti.com/api/v1/accounts/" + item.account_id + "/conversations/" + item.conversation_id + "/messages",
    headers: { "api_access_token": item.chatwoot_api_token, "Content-Type": "application/json" },
    body: JSON.stringify({ content: _msgText, message_type: "outgoing", private: false })
  });
} catch(_ce) {}
return [{ json: item }];

// EXPLICAR AGENDAMIENTO / INICIAR FUNNEL BOOKING
const ctx = $input.first().json;
const botConfig = ctx.bot_config || {};

// ── SKIP: ya en preferencia de tiempo o cambio de dia ───────────────────
if (ctx.intent === "BOOKING_TIME_PREF" || ctx._booking_funnel_state === "awaiting_time_pref" || ctx.day_change_request === true) {
  return [{ json: Object.assign({}, ctx, { _booking_service: ctx._booking_service || (isDemoMode ? "Demo SofIA" : "Consulta general") }) }];
}

// ── DEMO LEAD CAPTURE ───────────────────────────────────────────────────
if (isDemoMode) {

  // Step 2: usuario acaba de enviar su nombre y clinica
  if (ctx._demo_capture === true) {
    const rawMsg = (ctx.message_text || "").trim();
    var demoName = rawMsg;
    var demoClinic = "";
    var seps = [", ", " / ", " - ", ","];
    for (var si = 0; si < seps.length; si++) {
      var sepIdx2 = rawMsg.indexOf(seps[si]);
      if (sepIdx2 > 0) { demoName = rawMsg.slice(0, sepIdx2).trim(); demoClinic = rawMsg.slice(sepIdx2 + seps[si].length).trim(); break; }
    }
    try {
      await this.helpers.httpRequest({ method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/labels",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: { labels: [] }, json: true });
      await this.helpers.httpRequest({ method: "PATCH",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id,
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ custom_attributes: { demo_name: demoName, demo_clinic: demoClinic, booking_funnel_state: "awaiting_time_pref", booking_service: "Demo SofIA" } }),
        json: false });
    } catch(e) {}
    return [{ json: Object.assign({}, ctx, { _funnel_started: true, _booking_service: "Demo SofIA", _demo_name: demoName, _demo_clinic: demoClinic }) }];
  }

  // Step 1: primera vez en demo (sin estado, sin servicio) -> pedir nombre y clinica
  if (!ctx._booking_service && !ctx._booking_funnel_state && ctx.intent === "CREATE_EVENT") {
    var ctaMsg = ["Perfecto! Para coordinar tu demo",
      "Cual es tu nombre y el nombre de tu clinica?",
      "Ej: Juan Lopez, Clinica Dental Norte"].join("\n\n");
    try {
      await this.helpers.httpRequest({ method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/messages",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ content: ctaMsg, message_type: "outgoing", private: false }),
        json: false });
      await this.helpers.httpRequest({ method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/labels",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: { labels: ["demo_capture"] }, json: true });
    } catch(e) {}
    return [{ json: Object.assign({}, ctx, { _funnel_started: true }) }];
  }
}
// ── END DEMO LEAD CAPTURE ────────────────────────────────────────────────

// Si _booking_service ya esta -> pasar directo
if (ctx._booking_service) {
  return [{ json: Object.assign({}, ctx, { _funnel_started: false, slot_service_hint: ctx._booking_service }) }];
}

// Primera vez -> enviar service picker

// Fallback sin Twilio
return [{ json: Object.assign({}, ctx, { _funnel_started: false }) }];

// LEER CITAS SUPABASE — filtra por doctor si hay doctor seleccionado
const ctx = $("Resolver Doctor").item.json;
const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;
const clinic_id    = ctx.clinic_id;
const selected_doctor = ctx.selected_doctor;

if (!clinic_id) {
  console.warn(JSON.stringify({ ts: new Date().toISOString(), event: "NO_CLINIC_ID" }));
  return [{ json: { no_appointments: true } }];
}

const now     = new Date();
const in30days = new Date(now.getTime() + 30 * 24 * 3600000);

var url = $env.N8N_SUPABASE_URL + "/rest/v1/appointments"
  + "?clinic_id=eq." + clinic_id
  + "&start_time=gte." + now.toISOString()
