// ── BOOKING_SERVICE: detectar servicio ───────────────────��────────────────
if (state === "awaiting_service" || ctx.intent === "BOOKING_SERVICE") {
  const svcMap = {
    "bk_limpieza":   "Limpieza dental",
    "bk_ortodoncia": "Ortodoncia",
