    else if (msg.includes("ortodoncia") || msg.includes("bracket") || msg.includes("aparato")) service = "Ortodoncia";
    else if (msg.includes("blanquea") || msg.includes("blanquear") || msg.includes("aclarar")) service = "Blanqueamiento dental";
    else if (msg.includes("implante")) service = "Implante dental";
