    else if (msg.includes("endodoncia") || msg.includes("nervio") || msg.includes("conducto")) service = "Endodoncia";
    else service = "Consulta general";
  }
  await saveToChat({ booking_funnel_state: "awaiting_time_pref", booking_service: service });
  if (botConfig.twilio_booking_time_sid) {
  }
