// ── BOOKING_TIME_PREF: detectar preferencia de tiempo ──────���────────��────
if (state === "awaiting_time_pref" || ctx.intent === "BOOKING_TIME_PREF" || ctx.day_change_request === true) {
  var _msgNT = msg.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  var _dowMap = { "lunes": 1, "martes": 2, "miercoles": 3, "jueves": 4, "viernes": 5, "sabado": 6 };

  // Helper: find next ISO date (Lima) for a given day-of-week
  var _findNextDow = function(dow) {
    var _nU = new Date(); var _nL = new Date(_nU.getTime() - 5 * 3600000);
    for (var _fi = 1; _fi <= 21; _fi++) {
      var _fd = new Date(_nL); _fd.setDate(_fd.getDate() + _fi); _fd.setHours(0,0,0,0);
      if (_fd.getDay() === dow) {
        return _fd.getUTCFullYear() + '-' + String(_fd.getUTCMonth()+1).padStart(2,'0') + '-' + String(_fd.getUTCDate()).padStart(2,'0');
      }
    }
    return null;
  };

  // ── Case A: User already chose a day (from picker or free-text day change) ──
  if (ctx._is_day_choice === true || ctx.day_change_request === true) {
    var _selDow = null; var _selIso = null;
    var _msgForDay = _msgNT.replace(/[^a-z0-9 ]/g, "").trim();
    Object.keys(_dowMap).forEach(function(d) { if (_msgForDay.includes(d)) _selDow = _dowMap[d]; });

    // If digit (1-6) selected, map via SOFIA_DAYS private note
    if (!_selDow && ctx._is_day_choice && /\b[1-6]\b/.test(_msgNT)) {
      var _dDigit = parseInt(_msgNT.match(/\b([1-6])\b/)[1]);
      try {
        var _mResp = await this.helpers.httpRequest({
          method: "GET",
          url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/messages",
          headers: { "api_access_token": botConfig.chatwoot_api_token }
        });
        var _msgs = (_mResp.payload || []);
        for (var _mi = _msgs.length - 1; _mi >= 0; _mi--) {
          var _mc = (_msgs[_mi].content || "");
          if (_mc.startsWith("SOFIA_DAYS:")) {
            try {
              var _od = JSON.parse(_mc.substring(11));
              var _of = _od.find(function(x) { return x.option === _dDigit; });
              if (_of) { _selDow = _of.dow; _selIso = _of.date_iso; }
            } catch(e2) {}
            break;
          }
        }
      } catch(e) {}
    }

    if (!_selIso && _selDow) _selIso = _findNextDow(_selDow);

    await saveToChat({ booking_funnel_state: "awaiting_slot", conversation_state: "awaiting_slot" });
    // Remove awaiting_day_choice label, add awaiting_slot
    var _labelsAfter = ((ctx.raw_payload && ctx.raw_payload.conversation && ctx.raw_payload.conversation.labels) || [])
      .filter(function(l) { return l !== "awaiting_day_choice"; });
    if (!_labelsAfter.includes("awaiting_slot")) _labelsAfter.push("awaiting_slot");
    await setLabel(_labelsAfter);
    return [{ json: Object.assign({}, ctx, {
      _continue_to_slots: true,
      _booking_service: ctx._booking_service || ctx._bfSvc || "Consulta general",
      filter_specific_day: _selIso,
      preferred_dow: _selDow ? [_selDow] : null,
      time_pref_max_days: 14,
      time_pref_offset: 0
    }) }];
  }

  // ── Case B: Received time preference → show day picker ──
  var _maxDays = 14; var _offsetDays = 0;
  if (msg === "time_this_week" || _msgNT.includes("esta semana") || _msgNT.includes("pronto") || _msgNT.includes("antes posible")) {
    _maxDays = 7; _offsetDays = 0;
  } else if (msg === "time_next_week" || _msgNT.includes("proxima semana") || _msgNT.includes("siguiente semana")) {
    _maxDays = 7; _offsetDays = 7;
  }

  var _nowU = new Date(); var _nowL = new Date(_nowU.getTime() - 5 * 3600000);
  var _dNames = ["Domingo","Lunes","Martes","Miércoles","Jueves","Viernes","Sábado"];
  var _mNames = ["ene","feb","mar","abr","may","jun","jul","ago","sep","oct","nov","dic"];
  var _offered = []; var _pickerTxt = "\ud83d\udcc5 *¿Qué día prefieres?*\n\n";

  for (var _pi = _offsetDays; _pi < _offsetDays + _maxDays && _offered.length < 6; _pi++) {
    var _ld = new Date(_nowL); _ld.setDate(_ld.getDate() + _pi + 1); _ld.setHours(0,0,0,0);
    var _dow = _ld.getDay();
    if (_dow === 0) continue; // skip Sunday
    var _lbl = _dNames[_dow] + " " + _ld.getDate() + " " + _mNames[_ld.getMonth()];
    var _iso = _ld.getUTCFullYear() + '-' + String(_ld.getUTCMonth()+1).padStart(2,'0') + '-' + String(_ld.getUTCDate()).padStart(2,'0');
    _offered.push({ option: _offered.length + 1, dow: _dow, label: _lbl, date_iso: _iso });
    _pickerTxt += "*" + _offered.length + ".* " + _lbl + "\n";
  }
  _pickerTxt += "\nResponde con el número o el nombre del día \ud83d\ude0a";

  // Save offered days as private note (for digit-to-day mapping)
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/messages",
      headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
      body: JSON.stringify({ content: "SOFIA_DAYS:" + JSON.stringify(_offered), message_type: "outgoing", private: true }),
      json: false
    });
