// [J] MOSTRAR SLOTS — consulta real en Supabase
const handleMostrarSlots = async function() {
  var waLabel = id === "wa_count_1" ? "1 número" : id === "wa_count_varios" ? "2-5 números" : "más de 5";

  // Compute candidate slots: next 14 days, Mon-Fri, 10am/11am/2pm/3pm GMT-5
  // GMT-5 midnight = 05:00 UTC. Slot at H:00 GMT-5 = (H+5):00 UTC same calendar day.
  var now = new Date();
  var GM5_S = 5 * 3600; // 5h in seconds
  var currentDayGMT5 = Math.floor((Math.floor(now.getTime() / 1000) - GM5_S) / 86400);
  var dayNamesArr = ["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"];
  var monthNamesArr = ["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"];

  var candidates = [];
  for (var di = 1; di <= 14 && candidates.length < 10; di++) {
    var dayNumber = currentDayGMT5 + di;
    // Midnight GMT-5 = 05:00 UTC of that day
    var dayMidnightUTC = new Date((dayNumber * 86400 + GM5_S) * 1000);
    var dow = dayMidnightUTC.getUTCDay();
    if (dow === 0 || dow === 6) continue; // skip weekend

    var dayNum = dayMidnightUTC.getUTCDate();
    var monthIdx = dayMidnightUTC.getUTCMonth();
    var dateLabel = dayNamesArr[dow] + " " + dayNum + " " + monthNamesArr[monthIdx];

    var hoursGMT5 = [10, 11, 14, 15];
    for (var ji = 0; ji < hoursGMT5.length; ji++) {
      var h = hoursGMT5[ji];
      // H:00 GMT-5 = (H+5):00 UTC on the same UTC day as dayMidnightUTC
      var slotUTC = new Date(dayMidnightUTC.getTime() + h * 3600 * 1000);
      if (slotUTC.getTime() <= now.getTime() + 2 * 3600 * 1000) continue; // need 2h buffer
      var timeLabel = (h <= 12 ? h : h - 12) + ":00 " + (h < 12 ? "AM" : "PM");
      candidates.push({ utc: slotUTC.toISOString(), label: dateLabel + " · " + timeLabel });
      if (candidates.length >= 10) break;
    }
  }

  // Query Supabase for booked demo_call slots
  var bookedSet = {};
  if (candidates.length > 0) {
    try {
      var fromISO = candidates[0].utc;
      var toISO = candidates[candidates.length - 1].utc;
      var booked = await this.helpers.httpRequest({
        method: "GET",
        url: SUPA_URL + "/rest/v1/appointments?clinic_id=eq." + DEMO_CLINIC_ID +
             "&service=eq.demo_call&start_time=gte." + fromISO +
             "&start_time=lte." + toISO + "&status=neq.cancelled&select=start_time",
        headers: { "apikey": SUPA_KEY, "Authorization": "Bearer " + SUPA_KEY }
      });
      if (Array.isArray(booked)) {
        booked.forEach(function(r) { bookedSet[r.start_time] = true; });
      }
    } catch(e) {}
  }

  var free = candidates.filter(function(s) { return !bookedSet[s.utc]; }).slice(0, 5);

  if (free.length === 0) {
    await sendText.call(this,
      "En este momento no tenemos horarios disponibles en las próximas 2 semanas 😔" + NL + NL +
