var available_slots = [];

if (mode === "legacy" || available_doctors.length === 0) {
  // No doctors configured — use clinic business hours
  available_slots = buildLegacySlots(busyGeneral, ctx.bot_config); // slice after filter

} else if (mode === "specific" && selected_doctor) {
  // Specific doctor requested
  var busy = busyByDoctor[selected_doctor.id] || [];
  available_slots = buildDoctorSlots(selected_doctor, busy); // slice after filter

} else {
  // "any" mode — compute slots for all doctors, sort chronologically
  for (var di = 0; di < available_doctors.length; di++) {
    var doc = available_doctors[di];
    var dBusy = busyByDoctor[doc.id] || [];
    var dSlots = buildDoctorSlots(doc, dBusy);
    for (var si = 0; si < dSlots.length; si++) available_slots.push(dSlots[si]);
  }
  available_slots.sort(function(a, b) { return new Date(a.start) - new Date(b.start); });; // slice after filter
}

// Apply specific day filter (user chose a day from day picker)
if (_filterDay) {
  available_slots = available_slots.filter(function(s) {
    var slotLima = new Date(new Date(s.start).getTime() - OFFSET_HOURS * 3600000);
    var sStr = slotLima.getUTCFullYear() + '-' + String(slotLima.getUTCMonth()+1).padStart(2,'0') + '-' + String(slotLima.getUTCDate()).padStart(2,'0');
    return sStr === _filterDay;
