            headers: {
                'apikey':        SERVICE_KEY,
                'Authorization': 'Bearer ' + SERVICE_KEY,
                'Content-Type':  'application/json'
            },
            body,
            json: true
        });
    }, {
        attempts,
        baseMs: 500,
        noRetryOn: ['400', '422', '409']  // Errores de validación → no reintentar
    });
};
