  if (adminPhone) {
    const normalizedRaw   = rawPhone.replace(/^whatsapp:/, '').replace(/^\+/, '');
    const normalizedAdmin = adminPhone.replace(/^\+/, '');
    if (normalizedRaw === normalizedAdmin) {
