  else if (plan === "comparar") { planText = "\uD83D\uDCCB *Comparativa de planes*\n\n\uD83D\uDFE2 B\u00E1sico \u2192 S/290/mes \u2192 500 conversaciones\n\uD83D\uDD35 Pro \u2192 S/490/mes \u2192 1,500 conversaciones\n\uD83D\uDFE3 Cl\u00ednica \u2192 S/790 \u2192 Ilimitadas\n\n\u2728 Sin contrato de permanencia. Cancela cuando quieras.\n\uD83D\uDCA1 Descuento 15% pagando 6 meses | 25% pagando 1 a\u00F1o\n\n\u00BFHablamos con un asesor para elegir el mejor? \uD83E\uDD1D"; }
  else { planText = "\uD83D\uDCB0 *Planes de SofIA AI*\n\n\uD83D\uDFE2 Plan B\u00E1sico: S/290/mes \u2014 500 conversaciones\n\uD83D\uDD35 Plan Pro: S/490/mes \u2014 1,500 conversaciones \u2B50\n\uD83D\uDFE3 Enterprise: S/790/mes \u2014 ilimitadas\n\nSin contrato. Cancela cuando quieras.\n\n\u00BFQuieres hablar con un asesor para elegir el mejor plan? \uD83E\uDD1D"; }
  await sendText.call(this, planText);
  await sendTwilioTemplate.call(this, botConfig.twilio_followup_content_sid, {});
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DEMO_PLAN_RESPONSE_SENT" }) }];
}

// ── New Demo Flow Engine ─────────────────────────────────────────────────
const flowConfig = botConfig.demo_flow || null;
if (!flowConfig || !flowConfig.nodes) {
  // No demo flow config — fallback
  return [{ json: ctx }];
}

// ── Lead capture state machine ───────────────────────────────────────────
if (intent === "DEMO_FLOW") {
  var leadState = convLabels.find(function(l) { return l.startsWith("df_lead_"); });
  if (leadState) {
    return await handleLeadCapture.call(this, "_LEAD_CAPTURE", null, flowConfig);
  }
}

// ── Resolve current state node ───────────────────────────────────────────
var currentNodeId = getDemoState() || flowConfig.start_node;
var currentNode = flowConfig.nodes[currentNodeId];

// ── DEMO_FLOW_START: show bienvenida ─────────────────────────────────────
if (intent === "DEMO_FLOW_START") {
  var startId = flowConfig.start_node;
  await sendDemoNode.call(this, startId, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_BIENVENIDA_SENT", skip_ai: true }) }];
}

// ── DEMO_FLOW_CATCH_ALL: re-send current node ────────────────────────────
if (intent === "DEMO_FLOW_CATCH_ALL") {
  var catchNodeId = currentNodeId || flowConfig.catch_all_node;
  await sendText.call(this, "\uD83D\uDC49 Por favor elige una de las opciones del men\u00FA:");
  await sendDemoNode.call(this, catchNodeId, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_CATCH_ALL_RESENT", skip_ai: true }) }];
}

// ── DEMO_FLOW: user selected pos_1..pos_5 ────────────────────────────────
if (intent === "DEMO_FLOW") {
  // Reopen conversation if it was set to pending (e.g. by _HUMAN action)
  if (ctx.conversation_status === "pending") {
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/toggle_status",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ status: "open" }),
        json: false
      });
    } catch(e) { /* non-critical */ }
  }
  // ── FIX: DF_LEAD_CAPTURE_STATE — user responded to lead capture form ──────
  // Pre-Clasificador routes df_lead_* messages here without demo_pos.
  // Must be handled before the pos-based navigation check below.
  if (ctx.classified_by === "DF_LEAD_CAPTURE_STATE") {
    return await handleLeadCapture.call(this, "_LEAD_CAPTURE", null, flowConfig);
  }
  var pos = ctx.demo_pos;
  if (!currentNode || !pos) {
    await sendDemoNode.call(this, flowConfig.start_node, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_FALLBACK_START", skip_ai: true }) }];
  }
  // Find selected option (pos is 1-based index)
  var selectedOption = currentNode.options[pos - 1] || null;
  if (!selectedOption) {
    await sendText.call(this, "\uD83D\uDC49 Por favor elige una de las opciones disponibles:");
    await sendDemoNode.call(this, currentNodeId, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_INVALID_POS", skip_ai: true }) }];
  }

  // Execute action or navigate to next node
  var action = selectedOption.action || null;
  var nextNodeId = selectedOption.next || null;

  if (action === "_HUMAN") {
    await transitionToNode.call(this, null);
    await sendText.call(this, "👤 ¡Genial! Te conecto directamente con nuestro asesor.\n\n📲 Escríbele por WhatsApp ahora mismo:\nhttps://wa.me/51905858566?text=Hola%2C%20vi%20la%20demo%20de%20SofIA%20AI%20y%20quiero%20m%C3%A1s%20informaci%C3%B3n\n\nTe responderá en minutos. ¡Gracias por tu interés! 🙌");
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/toggle_status",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ status: "pending" }),
        json: false
      });
    } catch(e) { console.error("_HUMAN toggle status error:", e.message); }
    // Private note so asesor has context
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: "https://chat.redsolucionesti.com/api/v1/accounts/" + ctx.account_id + "/conversations/" + ctx.conversation_id + "/messages",
        headers: { "api_access_token": botConfig.chatwoot_api_token, "Content-Type": "application/json" },
        body: JSON.stringify({ content: "🤝 LEAD SOLICITA ASESOR (desde demo SofIA)\nContacto: " + (ctx.contact_phone || ctx.sender_name || "desconocido"), message_type: "outgoing", private: true }),
        json: false
      });
    } catch(e) {}
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_ACTION_HUMAN_SENT", skip_ai: true }) }];
  }

  if (action === "_CREATE_EVENT") {
    await transitionToNode.call(this, null);
    // Mark conversation_metrics as CREATE_EVENT so re-engagement cron tracks demo leads
    // who start the booking funnel but abandon before picking a slot.
    try {
      var _sbUrl = $env.N8N_SUPABASE_URL;
      var _sbKey = $env.N8N_SUPABASE_SERVICE_KEY;
      if (_sbUrl && _sbKey && ctx.clinic_id && ctx.conversation_id) {
        await this.helpers.httpRequest({
          method: "POST",
          url: _sbUrl + "/rest/v1/conversation_metrics",
          headers: { apikey: _sbKey, Authorization: "Bearer " + _sbKey, "Content-Type": "application/json", Prefer: "resolution=merge-duplicates,return=minimal" },
          body: JSON.stringify({ clinic_id: ctx.clinic_id, conversation_id: parseInt(ctx.conversation_id, 10), intent: "CREATE_EVENT", booked: false }),
          json: false
        });
      }
    } catch(_me) { /* non-critical */ }
    // DEMO BOOKING: collect lead info first, then show calendar day picker
    // Fix: clear stale df_* from local convLabels snapshot (transitionToNode cleared them in Chatwoot
    // but local array is still dirty — causes handleLeadCapture to misread state e.g. treating
    // button payload "pos_1" as the user's name when df_lead_name label lingers)
    for (var _ci = convLabels.length - 1; _ci >= 0; _ci--) {
      if (convLabels[_ci].startsWith("df_")) convLabels.splice(_ci, 1);
    }
    var _hasLeadData = convLabels.includes("lead_captured");
    if (!_hasLeadData) {
      // Lead info not collected yet — start multi-step form
      return await handleLeadCapture.call(this, "_LEAD_CAPTURE", null, flowConfig);
    }
    // Lead already captured → go straight to LP5 day picker
    await sendText.call(this, "\u{1F4C5} Genial! Elijamos el d\u00EDa para tu demo:");
    return await sendDemoBookingDayPicker.call(this, botConfig, ctx);
  }

  if (action === "_LEAD_CAPTURE" || action === "_LEAD_CAPTURE_START") {
    return await handleLeadCapture.call(this, action, selectedOption, flowConfig);
  }

  if (nextNodeId && flowConfig.nodes[nextNodeId]) {
    await sendDemoNode.call(this, nextNodeId, flowConfig);
    return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_NAV_" + nextNodeId.toUpperCase(), skip_ai: true }) }];
  }

  // No action, no next → go back to bienvenida
  await sendDemoNode.call(this, flowConfig.start_node, flowConfig);
  return [{ json: Object.assign({}, ctx, { intent: "SUBMENU_AWAIT", classified_by: "DF_FALLBACK_BIENVENIDA", skip_ai: true }) }];
}

// Fallback — should not reach here
return [{ json: ctx }];

const SUPABASE_URL = $env.N8N_SUPABASE_URL;
const SERVICE_KEY  = $env.N8N_SUPABASE_SERVICE_KEY;

// Helper: llama Supabase RPC via httpRequest
async function supabaseRpc(fnName, params) {
  const supH = {
    apikey: SERVICE_KEY,
    Authorization: 'Bearer ' + SERVICE_KEY,
    'Content-Type': 'application/json'
  };
  return await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/rpc/' + fnName,
    headers: supH,
    body: params,
    json: true
  });
}

const ctx        = $input.first().json;
const clinicId   = ctx.clinic_id || ctx.resolved_clinic_id;
const adminPhone = ctx.contact_phone || '';
const action     = ctx.admin_action;
const botConfig  = ctx.bot_config || {};

if (!action) {
  const hint = '❓ No entendí. Responde con el botón ✅ Confirmar o ❌ Cancelar del mensaje de la cita.';
  await supabaseRpc.call(this, 'send_chatwoot_message', {
    p_conversation_id: ctx.governance_conversation_id,
    p_message: hint,
    p_private: false
  }).catch(() => {});
  return [{ json: { ...ctx, admin_handled: true, action: 'unknown' } }];
}

let notification = null;
try {
  const result = await supabaseRpc.call(this, 'get_pending_admin_notification', {
    p_admin_phone: adminPhone
  });
  notification = Array.isArray(result) ? result[0] : result;
} catch(e) {
  console.error(JSON.stringify({ event: 'ADMIN_REPLY_GET_NOTIF_ERR', error: e.message }));
}

if (!notification || !notification.notification_id) {
  const msg = '⚠️ No encontré ninguna cita pendiente de confirmación.';
  await supabaseRpc.call(this, 'send_chatwoot_message', {
    p_conversation_id: ctx.governance_conversation_id,
    p_message: msg,
    p_private: false
  }).catch(() => {});
  return [{ json: { ...ctx, admin_handled: true, action: 'no_pending' } }];
}

let resolveResult = null;
try {
  resolveResult = await supabaseRpc.call(this, 'resolve_admin_notification', {
    p_notification_id: notification.notification_id,
    p_action:          action
  });
} catch(e) {
  console.error(JSON.stringify({ event: 'ADMIN_REPLY_RESOLVE_ERR', error: e.message }));
}

const startTime  = new Date(notification.start_time);
const dateStr    = startTime.toLocaleDateString('es-PE', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Lima' });
const timeStr    = startTime.toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Lima' });
const firstName  = (notification.patient_name || 'Paciente').split(' ')[0];
const clinicName = ctx.clinic_name || 'la clínica';

return [{ json: {
  ...ctx,
  admin_handled:            true,
  action,
  resolved_appointment_id:  resolveResult && resolveResult.appointment_id,
  patient_phone:            notification.patient_phone,
  t13_vars: JSON.stringify({ '1': firstName, '2': dateStr + ' a las ' + timeStr, '3': clinicName }),
  t13_sid:  botConfig.twilio_patient_confirmed_sid || '',
  t14_vars: JSON.stringify({ '1': firstName, '2': dateStr + ' a las ' + timeStr, '3': clinicName }),
  patient_name:    notification.patient_name,
  start_time_iso:  notification.start_time,
  t14_sid:         botConfig.twilio_patient_cancelled_sid || '',
  admin_ack: action === 'confirmed'
    ? '✅ Cita confirmada. El paciente fue notificado.'
    : '❌ Cita cancelada. El paciente recibirá nuevos horarios disponibles.',
  twilio_from:         botConfig.twilio_from || 'whatsapp:+51977588512',
  twilio_account_sid:  botConfig.twilio_account_sid || 'AC4080780a4b4a7d8e7b107a39f01abad3'
} }];

// Calcular 3 slots disponibles para reagendar al paciente
const ctx      = $input.first().json;
const clinicId = ctx.clinic_id || ctx.resolved_clinic_id;

// Buscar citas existentes para los próximos 7 días
const now     = new Date();
const weekOut = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

let existingAppts = [];
try {
  existingAppts = await supabaseRpc('get_clinic_appointments_range', {
    p_clinic_id: clinicId,
    p_from: now.toISOString(),
    p_to:   weekOut.toISOString()
  }, { attempts: 1 });
  if (!Array.isArray(existingAppts)) existingAppts = [];
} catch(e) {}

// Generar slots: L-V 9am-6pm cada 30min, saltando ocupados
const bookedTimes = new Set(existingAppts.map(a => a.start_time));
const slots = [];
const cursor = new Date(now);
cursor.setMinutes(0, 0, 0);
if (cursor.getHours() >= 18) { cursor.setDate(cursor.getDate() + 1); cursor.setHours(9); }
else if (cursor.getHours() < 9) cursor.setHours(9);
else cursor.setHours(cursor.getHours() + 1);

while (slots.length < 3 && cursor < weekOut) {
  const dow = cursor.getDay(); // 0=Sun 6=Sat
  const h   = cursor.getHours();
  if (dow !== 0 && dow !== 6 && h >= 9 && h < 18) {
    const isoStr = cursor.toISOString();
    if (!bookedTimes.has(isoStr)) {
      const label = cursor.toLocaleString('es-PE', {
        weekday: 'short', day: 'numeric', month: 'short',
        hour: '2-digit', minute: '2-digit', timeZone: 'America/Lima'
      });
      slots.push({ label, iso: isoStr });
    }
  }
  cursor.setMinutes(cursor.getMinutes() + 30);
  if (cursor.getHours() >= 18) {
    cursor.setDate(cursor.getDate() + 1);
    cursor.setHours(9); cursor.setMinutes(0);
  }
}

// Fill missing slots with generic labels
while (slots.length < 3) slots.push({ label: 'Consultar horario', iso: null });

const firstName = (ctx.patient_name || 'Paciente').split(' ')[0];
const cancelledDate = new Date(ctx.start_time_iso).toLocaleDateString('es-PE', {
  weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Lima'
});

const t14Vars = JSON.stringify({
  "1": firstName,
  "2": cancelledDate,
  "3": slots[0].label,
  "4": slots[1].label,
  "5": slots[2].label
});

return [{ json: { ...ctx, t14_vars: t14Vars, rebook_slots: slots } }];
